import React, { useState } from 'react';
import { View, Text, TextInput, Button, Alert, ScrollView } from 'react-native';
import styles from '../styles';
import { EventAPI } from '../services';

export default function CadastroEventos({ navigation }: any) {
  const [title, setTitle] = useState('');
  const [date, setDate] = useState('');
  const [location, setLocation] = useState('');

  const handleSave = async () => {
    if (!title || !date) return Alert.alert('Atenção', 'Título e data são obrigatórios');
    const created = await EventAPI.create({ title, date, location });
    Alert.alert('Criado', 'Evento criado com sucesso');
    navigation.navigate('EventoDetail', { id: created.id });
  };

  return (
    <ScrollView style={styles.page} contentContainerStyle={{ padding: 16 }}>
      <View style={styles.card}>
        <Text style={styles.cardTitle}>Novo Evento</Text>

        <Text style={{ marginTop: 8 }}>Título</Text>
        <TextInput value={title} onChangeText={setTitle} placeholder="Ex: Casamento: Ana & João" style={{ borderBottomWidth: 1, paddingVertical: 6 }} />

        <Text style={{ marginTop: 12 }}>Data</Text>
        <TextInput value={date} onChangeText={setDate} placeholder="YYYY-MM-DD" style={{ borderBottomWidth: 1, paddingVertical: 6 }} />

        <Text style={{ marginTop: 12 }}>Local</Text>
        <TextInput value={location} onChangeText={setLocation} placeholder="Ex: Igreja Matriz" style={{ borderBottomWidth: 1, paddingVertical: 6 }} />

        <View style={{ height: 12 }} />
        <Button title="Salvar" onPress={handleSave} />
      </View>
    </ScrollView>
  );
}
